CREATE DATABASE `GPT_Filtre_Agr` DEFAULT CHARACTER SET utf8mb4;

USE `GPT_Filtre_Agr`;

DROP TABLE IF EXISTS coches;

CREATE TABLE coches (
  id_coche INT NOT NULL PRIMARY KEY,
  marca VARCHAR(30) NOT NULL,
  modelo VARCHAR(40) NOT NULL,
  anio SMALLINT NOT NULL,
  segmento VARCHAR(15) NOT NULL,
  carroceria VARCHAR(15) NOT NULL,
  combustible VARCHAR(12) NOT NULL,
  transmision VARCHAR(30) NOT NULL,
  traccion VARCHAR(10) NOT NULL,
  potencia_cv SMALLINT NOT NULL,
  consumo_l_100km DECIMAL(4,1) NOT NULL,
  emisiones_co2_g_km SMALLINT NOT NULL,
  color VARCHAR(12) NOT NULL,
  precio_eur INT NOT NULL,
  ciudad_registro VARCHAR(30) NOT NULL,
  INDEX idx_marca (marca),
  INDEX idx_anio (anio),
  INDEX idx_combustible (combustible),
  INDEX idx_ciudad (ciudad_registro),
  INDEX idx_segmento (segmento)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;






DROP TABLE IF EXISTS musica;

CREATE TABLE musica (
  id_cancion INT PRIMARY KEY,
  artista VARCHAR(50) NOT NULL,
  genero VARCHAR(20) NOT NULL,
  idioma VARCHAR(10) NOT NULL,
  formato VARCHAR(10) NOT NULL,
  sello_discografico VARCHAR(30) NOT NULL,
  pais_artista VARCHAR(30) NOT NULL,
  plataforma_principal VARCHAR(20) NOT NULL,
  anio_lanzamiento SMALLINT NOT NULL,
  duracion_segundos SMALLINT NOT NULL,
  popularidad TINYINT NOT NULL,
  streams_totales BIGINT NOT NULL,
  contenido_explicito BOOLEAN NOT NULL,
  numero_colaboraciones TINYINT NOT NULL,
  ingresos_estimados_usd INT NOT NULL,
  INDEX idx_artista (artista),
  INDEX idx_genero (genero),
  INDEX idx_anio (anio_lanzamiento),
  INDEX idx_plataforma (plataforma_principal)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;






DROP TABLE IF EXISTS viviendas;

CREATE TABLE viviendas (
  id_vivienda INT PRIMARY KEY,
  tipo_vivienda VARCHAR(15) NOT NULL,
  operacion VARCHAR(10) NOT NULL,
  ciudad VARCHAR(30) NOT NULL,
  barrio VARCHAR(30) NOT NULL,
  anio_construccion SMALLINT NOT NULL,
  superficie_m2 SMALLINT NOT NULL,
  habitaciones TINYINT NOT NULL,
  banos TINYINT NOT NULL,
  planta TINYINT NULL,
  ascensor BOOLEAN NOT NULL,
  estado_vivienda VARCHAR(15) NOT NULL,
  orientacion VARCHAR(10) NOT NULL,
  calificacion_energetica CHAR(1) NOT NULL,
  precio_eur INT NOT NULL,
  INDEX idx_ciudad (ciudad),
  INDEX idx_operacion (operacion),
  INDEX idx_tipo (tipo_vivienda),
  INDEX idx_precio (precio_eur)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;






